class RootDiscoveryTests(unittest.TestCase):
    """Wave 1p7pm: ``_discover_root`` resolves the served repo cwd-independently, anchored on the
    server script's OWN install location (``parents[3]`` of ``server_impl.py``). Priority:
    override → script-location → marker-validated host env vars → cwd-walkup → fallback. Because the
    REAL ``server_impl.__file__`` points at the live wavefoundry repo (which carries the marker), the
    env/cwd-branch tests patch ``server_impl.__file__`` to a markerless tree so those branches run."""

    @classmethod
    def setUpClass(cls):
        cls.srv = load_server()

    def setUp(self):
        self.srv = type(self).srv
        self.tmp = tempfile.TemporaryDirectory()
        self.root = Path(self.tmp.name).resolve()
        self._real_file = self.srv.__file__

    def tearDown(self):
        self.srv.__file__ = self._real_file
        self.tmp.cleanup()

    def _markerless_script_file(self) -> str:
        """A fake ``server_impl.py`` path whose ``parents[3]`` is a markerless tree (no
        workflow-config.json) so the script-location branch is skipped and env/cwd can be tested."""
        bare = self.root / "bare-tree"
        scripts = bare / ".wavefoundry" / "framework" / "scripts"
        scripts.mkdir(parents=True, exist_ok=True)
        return str(scripts / "server_impl.py")

    def test_override_path_used(self):
        _make_repo(self.root)
        result = self.srv._discover_root(override=str(self.root))
        self.assertEqual(result, self.root.resolve())

    def test_script_location_wins_independent_of_cwd(self):
        # server_impl.py at <repo>/.wavefoundry/framework/scripts/ → parents[3] is the repo; the
        # marker there makes it authoritative regardless of cwd / env.
        repo = self.root / "served-repo"
        scripts = repo / ".wavefoundry" / "framework" / "scripts"
        scripts.mkdir(parents=True, exist_ok=True)
        _make_repo(repo)  # marker at <repo>/docs/workflow-config.json
        elsewhere = self.root / "some" / "other" / "cwd"
        elsewhere.mkdir(parents=True, exist_ok=True)
        self.srv.__file__ = str(scripts / "server_impl.py")
        with patch("pathlib.Path.cwd", return_value=elsewhere), \
             patch.dict("os.environ", {"CLAUDE_PROJECT_DIR": str(elsewhere), "PROJECT_ROOT": str(elsewhere)}, clear=False):
            result = self.srv._discover_root()
        self.assertEqual(result, repo.resolve())

    def test_claude_project_dir_used_only_when_marker_present(self):
        # script-location markerless → fall through to env vars; CLAUDE_PROJECT_DIR is honored ONLY
        # when it carries the marker (a stray var must not mis-root us).
        self.srv.__file__ = self._markerless_script_file()
        # A markerless env-var target + a markerless cwd (fully isolated subtree) → the stray var is
        # ignored; the result is NOT the stray path.
        stray = self.root / "stray-no-marker"
        stray.mkdir(parents=True, exist_ok=True)
        isolated_cwd = self.root / "bare-tree" / "deep" / "cwd"  # under bare-tree (no marker anywhere up)
        isolated_cwd.mkdir(parents=True, exist_ok=True)
        with patch("pathlib.Path.cwd", return_value=isolated_cwd), \
             patch.dict("os.environ", {"CLAUDE_PROJECT_DIR": str(stray)}, clear=False):
            os.environ.pop("PROJECT_ROOT", None)
            os.environ.pop("REPO_ROOT", None)
            self.assertNotEqual(self.srv._discover_root(), stray.resolve())
        # With the marker, CLAUDE_PROJECT_DIR wins.
        marked = self.root / "claude-target"
        _make_repo(marked)
        with patch("pathlib.Path.cwd", return_value=isolated_cwd), \
             patch.dict("os.environ", {"CLAUDE_PROJECT_DIR": str(marked)}, clear=False):
            os.environ.pop("PROJECT_ROOT", None)
            os.environ.pop("REPO_ROOT", None)
            self.assertEqual(self.srv._discover_root(), marked.resolve())

    def test_env_var_project_root(self):
        self.srv.__file__ = self._markerless_script_file()
        _make_repo(self.root)
        with patch.dict("os.environ", {"PROJECT_ROOT": str(self.root)}, clear=False):
            os.environ.pop("CLAUDE_PROJECT_DIR", None)
            os.environ.pop("REPO_ROOT", None)
            result = self.srv._discover_root()
        self.assertEqual(result, self.root.resolve())

    def test_falls_back_to_cwd_when_no_config(self):
        self.srv.__file__ = self._markerless_script_file()
        _make_repo(self.root)  # cwd carries the marker
        with patch("pathlib.Path.cwd", return_value=self.root), \
             patch.dict("os.environ", {}, clear=False):
            for k in ("CLAUDE_PROJECT_DIR", "PROJECT_ROOT", "REPO_ROOT"):
                os.environ.pop(k, None)
            result = self.srv._discover_root()
        self.assertEqual(result, self.root.resolve())



class LayeredIndexTests(unittest.TestCase):
    @classmethod
    def setUpClass(cls):
        cls.srv = load_server()

    def setUp(self):
        self.srv = type(self).srv
        self.tmp = tempfile.TemporaryDirectory()
        self.root = _make_repo(Path(self.tmp.name))

    def tearDown(self):
        self.tmp.cleanup()

    def test_search_docs_merges_project_and_packaged_framework_index(self):
        # 1p4ww: framework seeds fold into the project docs index (no separate framework layer).
        _write_index_layer(
            self.root / ".wavefoundry" / "index",
            [
                {
                    "id": "project-doc",
                    "path": "docs/project.md",
                    "kind": "doc",
                    "language": None,
                    "lines": [1, 1],
                    "section": None,
                    "text": "project docs",
                },
                {
                    "id": "seed",
                    "path": ".wavefoundry/framework/seeds/010-install-wavefoundry.prompt.md",
                    "kind": "seed",
                    "language": None,
                    "lines": [1, 1],
                    "section": None,
                    "text": "framework seed",
                },
            ],
            [[1, 0], [1, 0]],
        )

        index = self.srv.WaveIndex(self.root)
        import numpy as np
        with patch.object(index, "_indexer_constant", return_value="test-model"):
            with patch.object(index, "_embed_query", return_value=np.array([1, 0], dtype=np.float32)):
                with patch.object(index, "_get_reranker", return_value=None):
                    results, _ = index.search_docs("framework project", top_n=5)

        paths = {result["path"] for result in results}
        self.assertIn("docs/project.md", paths)
        self.assertIn(".wavefoundry/framework/seeds/010-install-wavefoundry.prompt.md", paths)

    def test_folded_framework_seed_satisfies_seed_lookup(self):
        # 1p4ww: framework seeds live in the project docs index (folded, not a separate layer).
        _write_index_layer(
            self.root / ".wavefoundry" / "index",
            [{
                "id": "seed",
                "path": ".wavefoundry/framework/seeds/010-install-wavefoundry.prompt.md",
                "kind": "seed",
                "language": None,
                "lines": [1, 1],
                "section": None,
                "text": "install seed",
            }],
            [[1, 0]],
        )

        index = self.srv.WaveIndex(self.root)
        result = index.get_seed("install-wavefoundry")

        self.assertIsNotNone(result)
        self.assertEqual(result["path"], ".wavefoundry/framework/seeds/010-install-wavefoundry.prompt.md")

    def test_seed_lookup_tolerates_null_section(self):
        _write_index_layer(
            self.root / ".wavefoundry" / "index",
            [{
                "id": "seed",
                "path": ".wavefoundry/framework/seeds/010-install-wavefoundry.prompt.md",
                "kind": "seed",
                "language": None,
                "lines": [1, 1],
                "section": None,
                "text": "install seed",
            }],
            [[1, 0]],
        )

        index = self.srv.WaveIndex(self.root)
        result = index.get_seed("no-match")

        self.assertIsNone(result)

    def test_search_skips_layer_with_incompatible_vector_dimension(self):
        _write_index_layer(
            self.root / ".wavefoundry" / "index",
            [{
                "id": "project-doc",
                "path": "docs/project.md",
                "kind": "doc",
                "language": None,
                "lines": [1, 1],
                "section": None,
                "text": "project docs",
            }],
            [[1, 0]],
        )
        _write_index_layer(
            self.root / ".wavefoundry" / "framework" / "index",
            [{
                "id": "framework-doc",
                "path": "README.md",
                "kind": "doc",
                "language": None,
                "lines": [1, 1],
                "section": None,
                "text": "framework docs",
            }],
            [[1, 0, 0]],
        )

        index = self.srv.WaveIndex(self.root)
        import numpy as np
        with patch.object(index, "_indexer_constant", return_value="test-model"):
            with patch.object(index, "_embed_query", return_value=np.array([1, 0], dtype=np.float32)):
                with patch.object(index, "_get_reranker", return_value=None):
                    results, _ = index.search_docs("project", top_n=5)

        self.assertEqual([result["path"] for result in results], ["docs/project.md"])

    def test_seed_lookup_still_works_when_model_version_differs(self):
        _write_index_layer(
            self.root / ".wavefoundry" / "index",
            [{
                "id": "seed",
                "path": ".wavefoundry/framework/seeds/010-install-wavefoundry.prompt.md",
                "kind": "seed",
                "language": None,
                "lines": [1, 1],
                "section": None,
                "text": "install seed",
            }],
            [[1, 0]],
            model="old-model",
        )

        index = self.srv.WaveIndex(self.root)
        self.assertEqual(
            index.get_seed("install-wavefoundry")["path"],
            ".wavefoundry/framework/seeds/010-install-wavefoundry.prompt.md",
        )


    def test_search_docs_lexical_supports_prompt_kind(self):
        index = self.srv.WaveIndex(self.root)
        chunks = [
            {
                "id": "prompt",
                "path": "docs/prompts/prepare-wave.prompt.md",
                "kind": "prompt",
                "language": None,
                "lines": [1, 2],
                "section": "Purpose",
                "text": "prepare wave prompt",
            },
            {
                "id": "doc",
                "path": "docs/references/project-overview.md",
                "kind": "doc",
                "language": None,
                "lines": [1, 2],
                "section": "Overview",
                "text": "project overview",
            },
        ]

        with patch.object(index, "_live_docs_chunks", return_value=chunks):
            results = index.search_docs_lexical("prepare wave", kind="prompt")

        self.assertEqual([result["id"] for result in results], ["prompt"])

    def test_search_docs_lexical_supports_architecture_kind_by_path(self):
        index = self.srv.WaveIndex(self.root)
        chunks = [
            {
                "id": "arch",
                "path": "docs/architecture/current-state.md",
                "kind": "doc",
                "language": None,
                "lines": [1, 2],
                "section": "Runtime Topology",
                "text": "architecture topology",
            },
            {
                "id": "doc",
                "path": "docs/references/project-overview.md",
                "kind": "doc",
                "language": None,
                "lines": [1, 2],
                "section": "Overview",
                "text": "project overview",
            },
        ]

        with patch.object(index, "_live_docs_chunks", return_value=chunks):
            results = index.search_docs_lexical("topology", kind="architecture")

        self.assertEqual([result["id"] for result in results], ["arch"])


